#include <cuda_runtime.h>

__global__ void undistortKernel(unsigned char* input, unsigned char* output, int width, int height, float* map_x, float* map_y) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = blockIdx.y * blockDim.y + threadIdx.y;
    if (x < width && y < height) {
        float src_x = map_x[y * width + x];
        float src_y = map_y[y * width + x];
        // Bilinear interpolation
        int x0 = (int)src_x;
        int y0 = (int)src_y;
        int x1 = x0 + 1;
        int y1 = y0 + 1;
        float dx = src_x - x0;
        float dy = src_y - y0;

        unsigned char val = (1-dx)*(1-dy)*input[y0*width + x0] +
                            dx*(1-dy)*input[y0*width + x1] +
                            (1-dx)*dy*input[y1*width + x0] +
                            dx*dy*input[y1*width + x1];
        output[y*width + x] = val;
    }
}
